import apideck_unify
import inspect

client = apideck_unify.Apideck()

def search_methods(obj, path="client"):
    if not hasattr(obj, '__dir__'):
        return
    for name in dir(obj):
        if name.startswith('_'):
            continue
        try:
            attr = getattr(obj, name)
        except:
            continue
        if callable(attr):
            try:
                sig = inspect.signature(attr)
                params = sig.parameters
                if 'parent_folder_id' in params and 'name' in params:
                    print(f"Found: {path}.{name}")
                    print(f"Params: {list(params.keys())}")
            except ValueError:
                pass
        elif hasattr(attr, '__class__') and attr.__class__.__module__.startswith('apideck_unify'):
            if 'models' not in attr.__class__.__module__:
                search_methods(attr, f"{path}.{name}")

search_methods(client)
